@dataclass(frozen=True)
class SupportBundleDependencies:
    """Dependencies for the support bundle use case."""

    filesystem: Filesystem
    clock: Clock
    doctor_runner: DoctorRunner
    archive_writer: ArchiveWriter


@dataclass(frozen=True)
class SupportBundleRequest:
    """Inputs for generating a support bundle."""

    output_path: Path
    redact_paths: bool
    workspace_path: Path | None = None


@dataclass(frozen=True)
class SupportBundleResult:
    """Result of support bundle generation."""

    manifest: dict[str, Any]


def _load_user_config(filesystem: Filesystem, path: Path) -> dict[str, Any]:
    try:
        if not filesystem.exists(path):
            return {}
        content = filesystem.read_text(path)
        result = json.loads(content)
        if isinstance(result, dict):
            return result
        return {"error": "Config is not a dictionary"}
    except (OSError, json.JSONDecodeError):
        return {"error": "Failed to load config"}


def build_support_bundle_manifest(
    request: SupportBundleRequest,
    *,
    dependencies: SupportBundleDependencies,
) -> dict[str, Any]:
    """Assemble the support bundle manifest without writing files."""
    system_info = {
        "platform": __import__("platform").system(),
        "platform_version": __import__("platform").version(),
        "platform_release": __import__("platform").release(),
        "machine": __import__("platform").machine(),
        "python_version": __import__("sys").version,
        "python_implementation": __import__("platform").python_implementation(),
    }

    generated_at = dependencies.clock.now().isoformat()

    user_config_path = Path.home() / ".scc" / "config.json"
    user_config = _load_user_config(dependencies.filesystem, user_config_path)
    user_config = redact_secrets(user_config) if isinstance(user_config, dict) else user_config

    org_config_path = Path.home() / ".scc" / "org.json"
    org_config = _load_user_config(dependencies.filesystem, org_config_path)
    org_config = redact_secrets(org_config) if isinstance(org_config, dict) else org_config

    try:
        doctor_result = dependencies.doctor_runner.run(
            str(request.workspace_path) if request.workspace_path else None
        )
        doctor_data = build_doctor_json_data(doctor_result)
    except Exception as exc:
        doctor_data = {"error": f"Failed to run doctor: {exc}"}

    bundle_data: dict[str, Any] = {
        "generated_at": generated_at,
        "cli_version": __version__,
        "system": system_info,
        "config": user_config,
        "org_config": org_config,
        "doctor": doctor_data,
    }

    if request.workspace_path:
        bundle_data["workspace"] = str(request.workspace_path)

    if request.redact_paths:
        bundle_data = redact_paths(bundle_data)

    return bundle_data


def create_support_bundle(
    request: SupportBundleRequest,
    *,
    dependencies: SupportBundleDependencies,
) -> SupportBundleResult:
    """Generate a support bundle and write the archive manifest."""
    manifest = build_support_bundle_manifest(request, dependencies=dependencies)
    manifest_json = json.dumps(manifest, indent=2)

    try:
        dependencies.archive_writer.write_manifest(str(request.output_path), manifest_json)
    except Exception as exc:
        raise SCCError(
            user_message="Failed to write support bundle",
            suggested_action="Check the output path and try again",
            debug_context=str(exc),
        ) from exc

    return SupportBundleResult(manifest=manifest)

            self.user_message = self.reason


@dataclass
class LaunchPolicyBlockedError(LaunchPreflightError):
    """Launch cannot proceed under the current network policy."""

    user_message: str = field(default="")
    suggested_action: str = field(
        default=(
            "Choose a less restrictive network policy or use a provider whose "
            "required destination sets are allowed."
        )
    )

    def __post_init__(self) -> None:
        if not self.user_message:
            required = ", ".join(self.required_destination_sets) or "none"
            provider = self.provider_id or "unknown"
            policy = self.network_policy or "unknown"
            self.user_message = (
                f"Launch blocked before startup: provider '{provider}' requires "
                f"destination sets [{required}] but the current network policy is '{policy}'."
            )


@dataclass
class LaunchAuditWriteError(ConfigError):
    """Launch audit event could not be persisted."""

    audit_destination: str = ""
    event_type: str = ""
    reason: str = ""
    user_message: str = field(default="")
    suggested_action: str = field(
        default="Check that SCC's local audit path exists and is writable, then retry."
    )

    def __post_init__(self) -> None:
        if not self.user_message:
            destination = self.audit_destination or "the configured audit sink"
            self.user_message = f"Failed to write launch audit event to {destination}."
        if not self.debug_context:
            details = []
            if self.event_type:
                details.append(f"event_type={self.event_type}")
            if self.reason:
                details.append(f"error={self.reason}")
            if details:
                self.debug_context = "\n".join(details)


@dataclass
class LaunchAuditUnavailableError(ConfigError):
    """Launch auditing is required but the sink is not wired."""

    user_message: str = field(default="Launch audit sink is not configured.")
    suggested_action: str = field(
        default="Use the SCC-wired launch dependency builder so preflight can audit before startup."
    )

"""Port for durable audit-event persistence."""

from __future__ import annotations

from typing import Protocol

from scc_cli.core.contracts import AuditEvent


class AuditEventSink(Protocol):
    """Persist canonical audit events to a durable sink."""

    def append(self, event: AuditEvent) -> None:
        """Append one audit event to the sink."""

    def describe_destination(self) -> str:
        """Return a human-readable destination description for error messages."""

from __future__ import annotations

import json
import platform
import re
import sys
import zipfile
from datetime import datetime, timezone
from pathlib import Path
from typing import Any

from scc_cli import __version__, config
from scc_cli.doctor.core import run_doctor
from scc_cli.doctor.serialization import build_doctor_json_data

SECRET_KEY_PATTERNS = [
    r"^auth$",
    r".*token.*",
    r".*api[_-]?key.*",
    r".*apikey.*",
    r".*password.*",
    r".*secret.*",
    r"^authorization$",
    r".*credential.*",
]

_SECRET_PATTERNS = [re.compile(pattern, re.IGNORECASE) for pattern in SECRET_KEY_PATTERNS]


def _is_secret_key(key: str) -> bool:
    return any(pattern.match(key) for pattern in _SECRET_PATTERNS)


def redact_secrets(data: dict[str, Any]) -> dict[str, Any]:
    """Redact secret values from a dictionary."""

    result: dict[str, Any] = {}

    for key, value in data.items():
        if _is_secret_key(key) and isinstance(value, str):
            result[key] = "[REDACTED]"
        elif isinstance(value, dict):
            result[key] = redact_secrets(value)
        elif isinstance(value, list):
            result[key] = [
                redact_secrets(item) if isinstance(item, dict) else item for item in value
            ]
        else:
            result[key] = value

    return result


def redact_paths(data: dict[str, Any], redact: bool = True) -> dict[str, Any]:
    """Redact home directory paths from a dictionary."""

    if not redact:
        return data

    home = str(Path.home())
    result: dict[str, Any] = {}

    for key, value in data.items():
        if isinstance(value, str) and home in value:
            result[key] = value.replace(home, "~")
        elif isinstance(value, dict):
            result[key] = redact_paths(value, redact=redact)
        elif isinstance(value, list):
            result[key] = [
                redact_paths(item, redact=redact)
                if isinstance(item, dict)
                else (item.replace(home, "~") if isinstance(item, str) and home in item else item)
                for item in value
            ]
        else:
            result[key] = value

    return result


def build_bundle_data(
    redact_paths_flag: bool = True,
    workspace_path: Path | None = None,
) -> dict[str, Any]:
    """Build support bundle data."""

    system_info = {
        "platform": platform.system(),
        "platform_version": platform.version(),
        "platform_release": platform.release(),
        "machine": platform.machine(),
        "python_version": sys.version,
        "python_implementation": platform.python_implementation(),
    }

    generated_at = datetime.now(timezone.utc).isoformat()

    try:
        user_config = config.load_user_config()
        if isinstance(user_config, dict):
            user_config = redact_secrets(user_config)
    except Exception:
        user_config = {"error": "Failed to load config"}

    try:
        org_config = config.load_cached_org_config()
        if org_config:
            org_config = redact_secrets(org_config)
    except Exception:
        org_config = {"error": "Failed to load org config"}

    try:
        doctor_result = run_doctor(workspace_path)
        doctor_data = build_doctor_json_data(doctor_result)
    except Exception as exc:
        doctor_data = {"error": f"Failed to run doctor: {exc}"}

    bundle_data: dict[str, Any] = {
        "generated_at": generated_at,
        "cli_version": __version__,
        "system": system_info,
        "config": user_config,
        "org_config": org_config,
        "doctor": doctor_data,
    }

    if workspace_path:
        bundle_data["workspace"] = str(workspace_path)

    if redact_paths_flag:
        bundle_data = redact_paths(bundle_data)

    return bundle_data


def get_default_bundle_path() -> Path:
    """Get default path for support bundle."""

    timestamp = datetime.now().strftime("%Y%m%d-%H%M%S")
    return Path.cwd() / f"scc-support-bundle-{timestamp}.zip"


def create_bundle(
    output_path: Path,
    redact_paths_flag: bool = True,
    workspace_path: Path | None = None,
) -> dict[str, Any]:
    """Create a support bundle zip file."""

    bundle_data = build_bundle_data(
        redact_paths_flag=redact_paths_flag,
        workspace_path=workspace_path,
    )

    with zipfile.ZipFile(output_path, "w", zipfile.ZIP_DEFLATED) as bundle:
        manifest_json = json.dumps(bundle_data, indent=2)
        bundle.writestr("manifest.json", manifest_json)

    return bundle_data

    exported = 0
    if payload.repo_path.exists():
        import_result = import_profiles_from_repo(payload.repo_path, dry_run=False)
        imported = import_result.imported
    else:
        payload.repo_path.mkdir(parents=True, exist_ok=True)

    profiles = list_personal_profiles()
    if profiles:
        export_result = export_profiles_to_repo(payload.repo_path, profiles)
        exported = export_result.exported

    _save_sync_repo_path(str(payload.repo_path))

    sync_result = ProfileSyncResult(
        mode=ProfileSyncMode.FULL_SYNC,
        repo_path=payload.repo_path,
        imported=imported,
        exported=exported,
    )

    return SettingsActionResult(
        status=SettingsActionStatus.SUCCESS,
        message=f"Synced: {imported} imported, {exported} exported",
        detail=sync_result,
        needs_ack=True,
    )


def _apply_support_bundle(request: SettingsChangeRequest) -> SettingsActionResult:
    payload = request.payload
    if not isinstance(payload, SupportBundlePayload):
        return SettingsActionResult(
            status=SettingsActionStatus.ERROR,
            message="Support bundle requires a payload",
            error="missing payload",
        )

    create_bundle(output_path=payload.output_path, redact_paths_flag=payload.redact_paths)
    info = SupportBundleInfo(output_path=payload.output_path)

    return SettingsActionResult(
        status=SettingsActionStatus.SUCCESS,
        message=f"Support bundle saved to {payload.output_path.name}",
        detail=info,
        needs_ack=True,
    )


def _load_version() -> str:
    try:
        return get_version("scc-cli")
    except PackageNotFoundError:
        return "unknown"

"""Function size guardrail test.

Enforces function size limits to maintain readability and modularity.
Functions exceeding 300 lines fail; functions between 200-300 lines produce warnings.

Metric: Physical lines per function using AST line numbers.
"""

from __future__ import annotations

import ast
import os
from pathlib import Path
from typing import NamedTuple

import pytest

# Thresholds
WARNING_THRESHOLD = 200
FAIL_THRESHOLD = 300

# Source directory to scan
SRC_DIR = Path(__file__).parent.parent / "src" / "scc_cli"

# Exclusion patterns (directories and file patterns to skip)
EXCLUDED_DIRS = {
    "tests",
    "migrations",
    "vendor",
    "schemas",
    ".venv",
    "build",
    "dist",
    "__pycache__",
}

EXCLUDED_FILE_PATTERNS = {
    "_pb2.py",  # protobuf generated
}


class FunctionInfo(NamedTuple):
    """Information about a function's size."""

    path: Path
    function_name: str
    line_count: int
    relative_path: str
    lineno: int


def should_exclude(file_path: Path) -> bool:
    """Check if a file should be excluded from size checks."""
    for part in file_path.parts:
        if part in EXCLUDED_DIRS:
            return True

    file_name = file_path.name
    for pattern in EXCLUDED_FILE_PATTERNS:
        if file_name.endswith(pattern):
            return True

    return False


def iter_functions(tree: ast.AST) -> list[tuple[str, int, int]]:
    """Yield function name, start line, and end line."""
    functions: list[tuple[str, int, int]] = []

    for node in ast.walk(tree):
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            if not hasattr(node, "end_lineno") or node.end_lineno is None:
                continue
            functions.append((node.name, node.lineno, node.end_lineno))

    return functions


def get_function_sizes(directory: Path) -> list[FunctionInfo]:
    """Get all functions in directory with their line counts."""
    functions: list[FunctionInfo] = []

    if not directory.exists():
        return functions

    for root, _dirs, filenames in os.walk(directory):
        root_path = Path(root)

        for filename in filenames:
            if not filename.endswith(".py"):
                continue

            file_path = root_path / filename

            if should_exclude(file_path):
                continue

            try:
                source = file_path.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue

            try:
                tree = ast.parse(source)
            except SyntaxError:
                continue

            for name, start, end in iter_functions(tree):
                line_count = end - start + 1
                try:
                    relative = file_path.relative_to(SRC_DIR.parent)
                except ValueError:
                    relative = file_path

                functions.append(
                    FunctionInfo(
                        path=file_path,
                        function_name=name,
                        line_count=line_count,
                        relative_path=str(relative),
                        lineno=start,
                    )
                )

    return functions


def categorize_functions(
    functions: list[FunctionInfo],
) -> tuple[list[FunctionInfo], list[FunctionInfo], list[FunctionInfo]]:
    """Categorize functions by size."""
    ideal_or_acceptable: list[FunctionInfo] = []
    warning_zone: list[FunctionInfo] = []
    failing: list[FunctionInfo] = []

    for function_info in functions:
        if function_info.line_count > FAIL_THRESHOLD:
            failing.append(function_info)
        elif function_info.line_count >= WARNING_THRESHOLD:
            warning_zone.append(function_info)
        else:
            ideal_or_acceptable.append(function_info)

    return ideal_or_acceptable, warning_zone, failing


def format_warning(function_info: FunctionInfo) -> str:
    """Format a warning message for a function in the warning zone."""
    return (
        f"WARNING: {function_info.relative_path}:{function_info.lineno} "
        f"{function_info.function_name} ({function_info.line_count} lines)\n"
        f"  Approaching {FAIL_THRESHOLD}-line limit. Please consider splitting.\n"
        f"  Current threshold: warning at {WARNING_THRESHOLD}, fail at {FAIL_THRESHOLD}"
    )


def format_failure(function_info: FunctionInfo) -> str:
    """Format a failure message for a function exceeding the limit."""
    return (
        f"FAIL: {function_info.relative_path}:{function_info.lineno} "
        f"{function_info.function_name} ({function_info.line_count} lines)\n"
        f"  Exceeds {FAIL_THRESHOLD}-line limit. Must be split.\n"
        f"  Current threshold: warning at {WARNING_THRESHOLD}, fail at {FAIL_THRESHOLD}"
    )


class TestFunctionSizes:
    """Test class for function size guardrails."""

    @pytest.mark.xfail(
        reason=(
            "Known large functions exceed guardrail (launch flow and org/reset commands). "
            "Tracked in maintainability refactor."
        )
    )
    def test_function_size_limits(self) -> None:
        """Verify all functions in src/scc_cli/ are within size limits."""
        functions = get_function_sizes(SRC_DIR)

        if not functions:
            pytest.skip(f"No functions found in {SRC_DIR}")

        ideal_or_acceptable, warning_zone, failing = categorize_functions(functions)

        print("\n" + "=" * 70)
        print("FUNCTION SIZE GUARDRAIL REPORT")
        print("=" * 70)

        if warning_zone:
            print(f"\n{'=' * 70}")
            print(f"WARNING ZONE ({WARNING_THRESHOLD}-{FAIL_THRESHOLD} lines)")
            print("=" * 70)
            for function_info in sorted(warning_zone, key=lambda x: -x.line_count):
                print(f"\n{format_warning(function_info)}")

        if failing:
            print(f"\n{'=' * 70}")
            print(f"FAILURES (>{FAIL_THRESHOLD} lines)")
            print("=" * 70)
            for function_info in sorted(failing, key=lambda x: -x.line_count):
                print(f"\n{format_failure(function_info)}")

        print(f"\n{'=' * 70}")
        print("SUMMARY")
        print("=" * 70)
        print(f"  Total functions scanned: {len(functions)}")
        print(f"  Ideal/Acceptable (<{WARNING_THRESHOLD} lines): {len(ideal_or_acceptable)}")
        print(f"  Warning zone ({WARNING_THRESHOLD}-{FAIL_THRESHOLD} lines): {len(warning_zone)}")
        print(f"  Failing (>{FAIL_THRESHOLD} lines): {len(failing)}")

        print(f"\n{'=' * 70}")
        print("TOP 5 LARGEST FUNCTIONS")
        print("=" * 70)
        sorted_functions = sorted(functions, key=lambda x: -x.line_count)[:5]
        for i, function_info in enumerate(sorted_functions, 1):
            status = (
                "FAIL"
                if function_info.line_count > FAIL_THRESHOLD
                else "WARN"
                if function_info.line_count >= WARNING_THRESHOLD
                else "OK"
            )
            print(
                "  "
                f"{i}. [{status}] {function_info.relative_path}:"
                f"{function_info.lineno} {function_info.function_name}: "
                f"{function_info.line_count} lines"
            )

        print("=" * 70 + "\n")

        if failing:
            failure_messages = [format_failure(f) for f in failing]
            pytest.fail(
                f"\n{len(failing)} function(s) exceed {FAIL_THRESHOLD} lines:\n\n"
                + "\n\n".join(failure_messages)
            )

